import React, { useState } from 'react';
import { Button, Select, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatVnd, formatDate, formatNumber } from '../../../utils/formatters';
import { exportExcel, MONTH_OPTIONS, YEAR_OPTIONS } from '../../../utils/exportExcel';
import styles from '../../../styles/erpReportPage.module.css';

import type { B01Row, B02Row, B03Row } from '../../../services/analytics/models';
const BaoCaoTaiChinhPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(now.getMonth() + 1);
  const [year, setYear] = useState(now.getFullYear());
  const [tab, setTab] = useState<'b01'|'b02'|'b03'>('b01');
  const [b01, setB01] = useState<B01Row[]>([]);
  const [b02, setB02] = useState<B02Row[]>([]);
  const [b03, setB03] = useState<B03Row[]>([]);
  const [loading, setLoading] = useState(false);
  React.useEffect(() => { let c=false; setLoading(true); const t=setTimeout(()=>{ const p={month,year};
    const req = tab==='b01'? analyticsService.getB01Dn(p): tab==='b02'? analyticsService.getB02Dn(p): analyticsService.getB03Dn({year});
    req.then(d=>{ if(!c){ if(tab==='b01') setB01(d as B01Row[]); else if(tab==='b02') setB02(d as B02Row[]); else setB03(d as B03Row[]);} })
      .catch(e=>{if(!c)dispatch(addToast({message:e?.message??'Lỗi',type:'error'}));}).finally(()=>{if(!c)setLoading(false);});
  },0); return ()=>{c=true;clearTimeout(t);}; }, [month,year,tab,dispatch]);
  const exportPath = tab==='b01'?'/reports/financial/b01-dn/export-excel': tab==='b02'?'/reports/financial/b02-dn/export-excel':'/reports/financial/b03-dn/export-excel';
  const rows = tab==='b01'? b01: tab==='b02'? b02: b03;
  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}><div className={styles.titleBlock}><h1 className={styles.title}><i className="fas fa-file-invoice-dollar" /> Báo cáo tài chính</h1><p className={styles.subtitle}>T{month}/{year}</p></div>
        <div className={styles.headerActions}><Select value={String(month)} onChange={e=>setMonth(Number(e.target.value))} options={MONTH_OPTIONS} size="small" /><Select value={String(year)} onChange={e=>setYear(Number(e.target.value))} options={YEAR_OPTIONS} size="small" />
          <Button variant="secondary" onClick={()=>exportExcel(exportPath, tab==='b03'?{year}:{month,year},`BC-TC-${tab}.xlsx`)}><i className="fas fa-file-excel" /> Xuất Excel</Button></div></div>
      <div className={styles.tabs}><button type="button" className={tab==='b01'?styles.tabActive:styles.tab} onClick={()=>setTab('b01')}>B01</button><button type="button" className={tab==='b02'?styles.tabActive:styles.tab} onClick={()=>setTab('b02')}>B02</button><button type="button" className={tab==='b03'?styles.tabActive:styles.tab} onClick={()=>setTab('b03')}>B03</button></div>
      <div className={styles.tableCard}>{loading?<div className={styles.loading}><i className="fas fa-spinner fa-spin" /></div>:rows.length===0?<div className={styles.empty}><p>Không có dữ liệu</p></div>:<div className={styles.tableWrapper}><table className={styles.table}><thead><tr><th>Chỉ tiêu</th>{tab==='b01'?<><th className={styles.colRight}>Nợ ĐK</th><th className={styles.colRight}>Có ĐK</th><th className={styles.colRight}>Nợ CK</th><th className={styles.colRight}>Có CK</th></>:<><th className={styles.colRight}>Kỳ này</th><th className={styles.colRight}>Kỳ trước</th></>}</tr></thead><tbody>
        {tab==='b01'? b01.map((r,i)=>(<tr key={i} className={r.isTotal?styles.rowTotal:undefined} style={{paddingLeft:(r.indent??0)*12}}><td>{r.code} — {r.name}</td><td className={styles.colRight}>{formatVnd(r.openingDebit)}</td><td className={styles.colRight}>{formatVnd(r.openingCredit)}</td><td className={styles.colRight}>{formatVnd(r.closingDebit)}</td><td className={styles.colRight}>{formatVnd(r.closingCredit)}</td></tr>))
        : tab==='b02'? b02.map((r,i)=>(<tr key={i} className={r.isTotal?styles.rowTotal:undefined}><td>{r.code} — {r.name}</td><td className={styles.colRight}>{formatVnd(r.currentAmount)}</td><td className={styles.colRight}>{formatVnd(r.previousAmount)}</td></tr>))
        : b03.map((r,i)=>(<tr key={i} className={r.isTotal?styles.rowTotal:undefined}><td>{r.code} — {r.name}</td><td className={styles.colRight}>{formatVnd(r.currentAmount)}</td><td className={styles.colRight}>{formatVnd(r.previousAmount)}</td></tr>))}
      </tbody></table></div>}</div>
    </div>
  );
};
export default BaoCaoTaiChinhPage;
